sql:
SELECT AVG(p.goals_scored) AS average_goals_by_top_scorer
FROM tournaments t
JOIN players p ON t.top_scorer_team_iso_code = p.team_iso_code AND t.top_scorer = p.player_name;

SELECT team
FROM world_cup_data
WHERE year = 2018;

SELECT SUM(goals_for) AS total_goals
  FROM world_cup_data
  WHERE year = 1930 AND team = 'Uruguay';

SELECT total_world_cup_appearances
FROM teams
WHERE iso_code = '0';

SELECT SUM(goals_for) AS total_goals
FROM world_cup_data
WHERE year = 1930;

SELECT team, COUNT(year) AS total_appearances
FROM world_cup_data
GROUP BY team;

